// src/store/bookingStore.js
const STORAGE_KEY = 'mizuya_bookings';
const BLOCKED_KEY = 'mizuya_blocked_dates';

// ─── Bookings ────────────────────────────────────────────────────────────────

export function getBookings() {
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]');
  } catch {
    return [];
  }
}

export function saveBooking(booking) {
  const bookings = getBookings();
  bookings.push(booking);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(bookings));
  window.dispatchEvent(new Event('mizuya:bookings-changed'));
}

export function updateBooking(id, patch) {
  const bookings = getBookings().map(b => b.id === id ? { ...b, ...patch } : b);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(bookings));
  window.dispatchEvent(new Event('mizuya:bookings-changed'));
}

export function cancelBooking(id) {
  updateBooking(id, { status: 'cancelled' });
}

export function togglePaid(id) {
  const booking = getBookings().find(b => b.id === id);
  if (booking) updateBooking(id, { paid: !booking.paid });
}

// ─── Blocked dates ────────────────────────────────────────────────────────────

export function getBlockedDates() {
  try {
    return new Set(JSON.parse(localStorage.getItem(BLOCKED_KEY) || '[]'));
  } catch {
    return new Set();
  }
}

export function toggleBlockedDate(dateStr) {
  const dates = getBlockedDates();
  if (dates.has(dateStr)) dates.delete(dateStr);
  else dates.add(dateStr);
  localStorage.setItem(BLOCKED_KEY, JSON.stringify([...dates]));
  window.dispatchEvent(new Event('mizuya:blocked-changed'));
}

// ─── Ref code generator ───────────────────────────────────────────────────────

export function generateRefCode() {
  return 'MZ-' + Math.random().toString(36).slice(2, 7).toUpperCase();
}
